const upsertGroupPolicies = `-- name: UpsertGroupPolicies :one
INSERT INTO group_policies (group_id, pricing_mode, menu_mode, inventory_mode, promotion_mode)
VALUES ($1, $2, $3, $4, $5)
ON CONFLICT (group_id)
DO UPDATE SET
  pricing_mode = EXCLUDED.pricing_mode,
  menu_mode = EXCLUDED.menu_mode,
  inventory_mode = EXCLUDED.inventory_mode,
  promotion_mode = EXCLUDED.promotion_mode
RETURNING group_id, pricing_mode, menu_mode, inventory_mode, promotion_mode
`

type UpsertGroupPoliciesParams struct {
	GroupID       int64  `json:"group_id"`
	PricingMode   string `json:"pricing_mode"`
	MenuMode      string `json:"menu_mode"`
	InventoryMode string `json:"inventory_mode"`
	PromotionMode string `json:"promotion_mode"`
}

// Group policies
func (q *Queries) UpsertGroupPolicies(ctx context.Context, arg UpsertGroupPoliciesParams) (GroupPolicy, error) {
	row := q.db.QueryRow(ctx, upsertGroupPolicies,
		arg.GroupID,
		arg.PricingMode,
		arg.MenuMode,
		arg.InventoryMode,
		arg.PromotionMode,
	)
	var i GroupPolicy
	err := row.Scan(
		&i.GroupID,
		&i.PricingMode,
		&i.MenuMode,
		&i.InventoryMode,
		&i.PromotionMode,
	)
	return i, err
}
